
.world-panel {
  padding: 10px 12px;
  background: linear-gradient(135deg, var(--c-rose) 0%, var(--c-parchment) 100%);
  border-bottom: 1px solid var(--c-rose-dark);
}

.world-row {
  display: flex;
  align-items: center;
  gap: 6px;
  margin-bottom: 4px;
  font-size: 12px;
}

.world-icon {
  font-size: 13px;
}

.world-text {
  color: var(--c-ink);
  font-weight: 600;
}

.world-divider {
  color: var(--c-rose-dark);
  margin: 0 4px;
}

.world-desc {
  font-size: 11px;
  color: var(--c-ink-light);
  margin-top: 4px;
  font-style: italic;
}
