
.status-panel {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.section {
  background: rgba(255, 255, 255, 0.6);
  border-radius: 6px;
  padding: 10px;
  border: 1px solid var(--c-rose-dark);
}

.section-title {
  font-size: 12px;
  font-weight: 700;
  color: var(--c-gold);
  margin-bottom: 8px;
  border-bottom: 1px dashed var(--c-rose-dark);
  padding-bottom: 4px;
}

.stat-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 8px;
}

.stat-item {
  display: flex;
  flex-direction: column;
  gap: 3px;
}

.stat-label {
  font-size: 11px;
  color: var(--c-ink-light);
}

.stat-value {
  font-size: 12px;
  font-weight: 700;
  color: var(--c-ink);
  text-align: right;
}

.stat-value.danger {
  color: var(--c-danger);
}

.info-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 6px;
}

.info-item {
  display: flex;
  justify-content: space-between;
  font-size: 12px;
}

.info-label {
  color: var(--c-ink-light);
}

.info-value {
  color: var(--c-ink);
  font-weight: 600;
}

.martial-list {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.martial-item {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 12px;
}

.martial-name {
  width: 80px;
  color: var(--c-ink);
  font-weight: 600;
}

.martial-bar {
  flex: 1;
  height: 6px;
  background: #e0d5d5;
  border-radius: 3px;
  overflow: hidden;
}

.martial-bar-fill {
  height: 100%;
  background: var(--c-gold);
  border-radius: 3px;
  transition: width 0.4s ease;
}

.martial-value {
  width: 30px;
  text-align: right;
  font-size: 11px;
  color: var(--c-ink-light);
}

.inventory-list {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.inventory-item {
  background: var(--c-rose);
  padding: 3px 8px;
  border-radius: 4px;
  font-size: 11px;
  display: flex;
  align-items: center;
  gap: 4px;
}

.inventory-name {
  color: var(--c-ink);
}

.inventory-count {
  color: var(--c-gold);
  font-weight: 700;
}
