
.harem-panel {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.section {
  background: rgba(255, 255, 255, 0.6);
  border-radius: 6px;
  padding: 10px;
  border: 1px solid var(--c-rose-dark);
}

.section-title {
  font-size: 12px;
  font-weight: 700;
  color: var(--c-gold);
  margin-bottom: 6px;
}

.progress-summary {
  display: flex;
  gap: 16px;
  font-size: 12px;
}

.progress-text {
  color: var(--c-ink);
}

.character-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.character-card {
  background: rgba(255, 255, 255, 0.8);
  border-radius: 6px;
  padding: 10px;
  border: 1px solid var(--c-rose-dark);
}

.char-header {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 6px;
}

.char-name {
  font-size: 13px;
  font-weight: 700;
  color: var(--c-ink);
}

.conquered-mark {
  margin-left: auto;
  font-size: 14px;
}

.char-bars {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.char-bar-row {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 11px;
}

.bar-label {
  width: 28px;
  color: var(--c-ink-light);
}

.char-bar {
  flex: 1;
  height: 6px;
  background: #e8e0e0;
  border-radius: 3px;
  overflow: hidden;
  position: relative;
}

.char-bar-fill {
  height: 100%;
  border-radius: 3px;
  transition: width 0.4s ease;
}

.char-bar-fill.affection {
  background: #e91e63;
  min-width: 2px;
}

.char-bar-fill.intimacy {
  background: #9c27b0;
}

.bar-value {
  width: 30px;
  text-align: right;
  color: var(--c-ink);
  font-weight: 600;
}

.bar-value.negative {
  color: var(--c-danger);
}

.char-relation {
  font-size: 11px;
  color: var(--c-ink-light);
  margin-top: 4px;
  font-style: italic;
}
